// src/presets/or-connector.js — runtime OpenRouter pricing/context refresh (v6.27.0)
//
// Phase 3 of the OR-stats system. Phase 2 (v6.26.0) shipped a static
// `presets/or-stats.json` baseline that's regenerated by a maintainer
// script. That baseline goes stale between releases — pricing changes,
// context windows grow, new models appear under existing slugs.
//
// This module adds an OPT-IN runtime refresh that hits OpenRouter's
// public `/api/v1/models` endpoint (CORS-permissive, no auth) and
// overlays its pricing/context onto the static stats. Popularity data
// (rank, weekly tokens, collection membership) STAYS static — that's
// not exposed via the public API, only via the rendered HTML on the
// rankings page, which we don't scrape.
//
// Design choices, locked in with the user during Phase 3 sign-off:
//   - Auto-fetch cadence: once per session, on the first preset-browser
//     open (when toggle ON). The cache lives across sessions for 24h.
//   - Failure modes:
//       offline / network error → silently skip, keep static stats
//       5xx / timeout (3s ceiling) → fall through, no cooldown
//       CORS or shape failure → 1-day cooldown (per user direction)
//       429 → 1-hour cooldown (rate-limit etiquette)
//   - Manual refresh: dedicated `↻ Refresh stats` button in the preset
//     browser toolbar, labeled (per user direction).
//
// The toggle is OFF by default. First-time users see a one-time prompt
// that explains what the connector does and lets them flip it on. The
// setup wizard also has a dedicated step for new installs.

import { getSettings, saveSettings } from '../settings.js';
import { log, warn } from '../logger.js';

// localStorage cache key + shape:
//   {
//     fetchedAt: ISO string,
//     expiresAt: ms epoch,
//     bySlug: { 'deepseek/deepseek-v3.2-...': { contextLength, pricing: {input,output} } }
//   }
const CACHE_KEY = 'sp_openrouter_cache_v1';
const TTL_MS = 24 * 60 * 60 * 1000; // 24 hours
const FETCH_TIMEOUT_MS = 3000;       // 3-second ceiling per Phase 3 design
const CORS_COOLDOWN_MS = 24 * 60 * 60 * 1000; // 1 day after CORS/shape failure
const RATE_LIMIT_COOLDOWN_MS = 60 * 60 * 1000; // 1 hour after 429
const OR_MODELS_URL = 'https://openrouter.ai/api/v1/models';

// Module-scoped session flag — once we've attempted an auto-refresh in
// this browser session, don't try again until the user manually clicks
// ↻ Refresh stats or opens a fresh tab.
let _sessionRefreshAttempted = false;

// In-memory mirror of the localStorage cache. Read once on first access
// to avoid re-parsing JSON on every getOrStats call.
let _cache = null;
let _cacheLoaded = false;

function _loadCacheFromLs() {
    if (_cacheLoaded) return _cache;
    _cacheLoaded = true;
    try {
        const raw = localStorage.getItem(CACHE_KEY);
        if (!raw) { _cache = null; return null; }
        const parsed = JSON.parse(raw);
        if (parsed && typeof parsed === 'object' && parsed.bySlug) {
            _cache = parsed;
            return parsed;
        }
    } catch {}
    _cache = null;
    return null;
}

function _writeCacheToLs(cache) {
    _cache = cache;
    try {
        localStorage.setItem(CACHE_KEY, JSON.stringify(cache));
    } catch (e) {
        warn('[or-connector] localStorage write failed:', e?.message || e);
    }
}

/**
 * Returns the cached runtime pricing/context map keyed by OR canonical_slug,
 * or null if no cache exists. Does NOT check expiry — callers that need
 * "fresh only" should use getRuntimeOverlay instead.
 */
export function getRawCache() {
    return _loadCacheFromLs();
}

/**
 * Returns the cached pricing/context overlay if it's still fresh (within
 * TTL), or null if no cache exists or it's expired. The registry merges
 * this onto the static stats when present so live pricing changes flow
 * through without a maintainer release.
 *
 * @returns {{ bySlug: object, fetchedAt: string } | null}
 */
export function getRuntimeOverlay() {
    const c = _loadCacheFromLs();
    if (!c) return null;
    if (typeof c.expiresAt !== 'number' || Date.now() > c.expiresAt) return null;
    return c;
}

/**
 * ISO timestamp of the most recent successful runtime refresh, or null.
 * Used by the preset-browser footer to show "auto-refreshed N hours ago".
 */
export function getLastRefreshAt() {
    const c = _loadCacheFromLs();
    return c?.fetchedAt || null;
}

function _now() { return Date.now(); }

function _cooldownActive(s) {
    const now = _now();
    if (typeof s._spOrConnectorCorsCooldownUntil === 'number' && s._spOrConnectorCorsCooldownUntil > now) return 'cors';
    if (typeof s._spOrConnectorRateCooldownUntil === 'number' && s._spOrConnectorRateCooldownUntil > now) return 'rate';
    return null;
}

function _setCooldown(s, kind, ms) {
    const until = _now() + ms;
    if (kind === 'cors') s._spOrConnectorCorsCooldownUntil = until;
    else if (kind === 'rate') s._spOrConnectorRateCooldownUntil = until;
    try { saveSettings(); } catch {}
}

/**
 * Refresh the runtime OR cache. Returns one of:
 *   { ok: true, refreshed: true,  count }   — fresh data fetched + stored
 *   { ok: true, refreshed: false, reason }  — skipped (disabled, cooldown,
 *                                              session-already-tried, fresh)
 *   { ok: false, reason, error? }            — fetch attempt failed
 *
 * @param {object} [opts]
 * @param {boolean} [opts.silent=true]  When true, skip if session already
 *   attempted; when false (manual refresh), always attempt and bypass
 *   cooldowns.
 * @param {boolean} [opts.force=false]  When true, bypass TTL/cooldown
 *   checks. Set by the manual refresh button.
 */
export async function refreshStats(opts = {}) {
    const silent = opts.silent !== false; // default true (auto-refresh)
    const force = !!opts.force;
    const s = getSettings();

    if (!force && !s.orConnectorEnabled) {
        return { ok: true, refreshed: false, reason: 'disabled' };
    }
    if (silent && _sessionRefreshAttempted) {
        return { ok: true, refreshed: false, reason: 'session-already-tried' };
    }
    if (!force) {
        const cool = _cooldownActive(s);
        if (cool) return { ok: true, refreshed: false, reason: 'cooldown:' + cool };
        const fresh = getRuntimeOverlay();
        if (silent && fresh) {
            // Cache is still good — no need to re-fetch on auto-refresh.
            // Manual refresh (force=true) bypasses this.
            return { ok: true, refreshed: false, reason: 'cache-fresh' };
        }
    }

    _sessionRefreshAttempted = true;

    let res;
    try {
        const ctrl = new AbortController();
        const timer = setTimeout(() => ctrl.abort(), FETCH_TIMEOUT_MS);
        try {
            res = await fetch(OR_MODELS_URL, { signal: ctrl.signal, credentials: 'omit' });
        } finally {
            clearTimeout(timer);
        }
    } catch (e) {
        // AbortError, network error, DNS failure, offline — silent skip.
        // No cooldown for transient failures (offline laptop, flaky wifi).
        const msg = e?.name === 'AbortError' ? 'timeout' : (e?.message || 'network');
        log('[or-connector] fetch failed (' + msg + ') — keeping static stats');
        return { ok: false, reason: 'network', error: msg };
    }

    if (res.status === 429) {
        _setCooldown(s, 'rate', RATE_LIMIT_COOLDOWN_MS);
        warn('[or-connector] rate-limited (429); cooldown 1h');
        return { ok: false, reason: 'rate-limit' };
    }
    if (res.status >= 500 && res.status < 600) {
        // Server-side outage — skip without cooldown so we retry next session.
        log('[or-connector] server error ' + res.status + ' — keeping static stats');
        return { ok: false, reason: 'server', error: 'HTTP ' + res.status };
    }
    if (!res.ok) {
        // 4xx other than 429 — likely shape change or auth surprise.
        // Treat as CORS/shape failure → 1-day cooldown.
        _setCooldown(s, 'cors', CORS_COOLDOWN_MS);
        warn('[or-connector] HTTP ' + res.status + ' — CORS-cooldown 1d');
        return { ok: false, reason: 'http', error: 'HTTP ' + res.status };
    }

    let json;
    try {
        json = await res.json();
    } catch (e) {
        _setCooldown(s, 'cors', CORS_COOLDOWN_MS);
        warn('[or-connector] response not JSON — CORS-cooldown 1d');
        return { ok: false, reason: 'parse', error: e?.message };
    }

    if (!json || !Array.isArray(json.data)) {
        _setCooldown(s, 'cors', CORS_COOLDOWN_MS);
        warn('[or-connector] response shape unexpected — CORS-cooldown 1d');
        return { ok: false, reason: 'shape' };
    }

    const bySlug = {};
    let count = 0;
    for (const m of json.data) {
        const slug = (m?.canonical_slug || m?.id || '').toLowerCase();
        if (!slug) continue;
        const pricing = m.pricing || {};
        const inputPerToken = parseFloat(pricing.prompt || pricing.input || '0') || 0;
        const outputPerToken = parseFloat(pricing.completion || pricing.output || '0') || 0;
        bySlug[slug] = {
            contextLength: typeof m.context_length === 'number' ? m.context_length : null,
            pricing: {
                input: Number((inputPerToken * 1e6).toFixed(4)),
                output: Number((outputPerToken * 1e6).toFixed(4)),
            },
        };
        count++;
    }

    const cache = {
        fetchedAt: new Date().toISOString(),
        expiresAt: _now() + TTL_MS,
        bySlug,
    };
    _writeCacheToLs(cache);

    // Clear cooldowns on success — a working refresh resets the timer.
    if (s._spOrConnectorCorsCooldownUntil || s._spOrConnectorRateCooldownUntil) {
        delete s._spOrConnectorCorsCooldownUntil;
        delete s._spOrConnectorRateCooldownUntil;
        try { saveSettings(); } catch {}
    }

    log('[or-connector] refreshed ' + count + ' models');
    return { ok: true, refreshed: true, count };
}

/**
 * Test-only: reset module state so tests start clean. NOT exported as
 * part of the public API.
 */
export function _resetForTests() {
    _sessionRefreshAttempted = false;
    _cache = null;
    _cacheLoaded = false;
}
